# TREND CHART  (simple line chart painted with QPainter)
# ==============================================================================
class _TrendChart(QtWidgets.QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setMinimumSize(200, 120)
        self._data     = TREND_DATA
        self._max_val  = 20
        self._labels   = [d[0] for d in self._data]
        self._started  = [d[1] for d in self._data]
        self._completed= [d[2] for d in self._data]

    def paintEvent(self, event):
        p = QtGui.QPainter(self)
        p.setRenderHint(QtGui.QPainter.RenderHint.Antialiasing)
        w, h   = self.width(), self.height()
        margin = {"l":30,"r":10,"t":10,"b":24}
        cw = w - margin["l"] - margin["r"]
        ch = h - margin["t"] - margin["b"]
        n  = len(self._data)

        # Grid lines
        p.setPen(QtGui.QPen(QtGui.QColor("#f3f4f6"), 1))
        for i in range(5):
            y = margin["t"] + int(i * ch / 4)
            p.drawLine(margin["l"], y, w - margin["r"], y)

        def to_pt(i, val):
            x = margin["l"] + int(i * cw / (n-1))
            y = margin["t"] + ch - int(val / self._max_val * ch)
            return QtCore.QPointF(x, y)

        # Draw lines
        for series, colour in [(self._started,"#10b981"),(self._completed,"#3b82f6")]:
            path = QtGui.QPainterPath()
            path.moveTo(to_pt(0, series[0]))
            for i in range(1, n):
                path.lineTo(to_pt(i, series[i]))
            p.setPen(QtGui.QPen(QtGui.QColor(colour), 2))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawPath(path)
            # Dots
            p.setBrush(QtGui.QColor(colour))
            p.setPen(Qt.PenStyle.NoPen)
            for i, val in enumerate(series):
                pt = to_pt(i, val)
                p.drawEllipse(pt, 3.5, 3.5)

        # X labels
        p.setPen(QtGui.QColor(_TEXT_GREY))
        p.setFont(QtGui.QFont("Segoe UI", 8))
        for i, lbl in enumerate(self._labels):
            x = margin["l"] + int(i * cw / (n-1))
            p.drawText(QtCore.QRectF(x-15, h-margin["b"]+4, 30, 16),
                       Qt.AlignmentFlag.AlignCenter, lbl)
        p.end()

