    # ──────────────────────────────────────────────────────────────────────────
    # TABLE
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data=None):
        rows = data if data is not None else self._attachees
        self.table.setRowCount(0)
        for i, at in enumerate(rows):
            num,name,reg,inst,dept,sup,start,end,status,gender = at
            self.table.insertRow(i)
            self.table.setRowHeight(i,46)

            for col,txt in [(0,str(num)),(2,reg),(4,dept),(5,sup),(6,start),(7,end)]:
                it = QtWidgets.QTableWidgetItem(txt)
                it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
                self.table.setItem(i,col,it)

            # Name with avatar circle
            name_w = QtWidgets.QWidget()
            name_hl = QtWidgets.QHBoxLayout(name_w)
            name_hl.setContentsMargins(6,0,6,0); name_hl.setSpacing(8)
            av = QtWidgets.QLabel(name[0])
            av.setFixedSize(26,26); av.setAlignment(Qt.AlignmentFlag.AlignCenter)
            colours = ["#3b82f6","#10b981","#f59e0b","#8b5cf6","#ef4444","#06b6d4"]
            av.setStyleSheet(f"background:{colours[i % len(colours)]};"
                             f"border-radius:13px;color:white;font-size:11px;font-weight:bold;")
            nl = QtWidgets.QLabel(name)
            nl.setStyleSheet(f"color:{_TEXT_DARK};font-size:11px;font-weight:600;")
            name_hl.addWidget(av); name_hl.addWidget(nl); name_hl.addStretch()
            self.table.setCellWidget(i,1,name_w)

            # Institution (col 3)
            it3 = QtWidgets.QTableWidgetItem(inst)
            it3.setFlags(it3.flags() & ~Qt.ItemFlag.ItemIsEditable)
            self.table.setItem(i,3,it3)

            # Status badge
            fg,bg = STATUS_COLOURS.get(status,(_TEXT_MID,"#f3f4f6"))
            self.table.setCellWidget(i,8,self._centre(_Badge(status,fg,bg)))

            # Actions
            self.table.setCellWidget(i,9,self._action_widget(i))

        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10,count)} of {count} attachees")

    def _action_widget(self, row):
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4,0,4,0); hl.setSpacing(4)
        for ico,tip,col,slot in [
            ("👁","View",  "#64748b", lambda _,r=row: self._on_view(r)),
            ("✏","Edit",  "#2563eb", lambda _,r=row: self._on_edit(r)),
            ("🗑","Delete","#dc2626", lambda _,r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico); b.setFixedSize(26,26)
            b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""QPushButton{{background:{col}22;color:{col};
                border:1px solid {col}44;border-radius:5px;font-size:12px;}}
                QPushButton:hover{{background:{col}44;}}""")
            b.clicked.connect(slot); hl.addWidget(b)
        hl.addStretch()
        return w

    @staticmethod
    def _centre(widget):
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft|Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6,0,0,0)
        return w

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _apply_filters(self):
        text = self.search_edit.text().lower()
        results = []
        for at in self._attachees:
            num,name,reg,inst,dept,sup,start,end,status,gender = at
            if text and not any(text in v.lower() for v in (name,reg,inst,dept,sup,status)): 
               continue
            results.append(at)
        self._populate_table(results)

    def _on_add(self):
        dlg = AddAttacheeDialog(self)
        dlg.attachee_saved.connect(self._append_attachee)
        dlg.exec()

    def _append_attachee(self, data):
        new_num = len(self._attachees) + 1
        reg_num = f"REG/2025/{new_num:03d}"
        self._attachees.insert(0,(
            new_num, data["name"], reg_num,
            data["institution"], data["department"],
            data["supervisor"], data["start_date"],
            data["end_date"], data["status"], data["gender"]
        ))
        self._populate_table()
        QtWidgets.QMessageBox.information(
            self,"Attach\u00e9 Added",
            f"✅  '{data['name']}' has been registered successfully.")

    def _on_view(self, row):
        if row >= len(self._attachees): return
        at = self._attachees[row]
        QtWidgets.QMessageBox.information(
            self,"Attach\u00e9 Details",
            f"<b>{at[1]}</b><br>Reg: {at[2]}<br>Institution: {at[3]}<br>"
            f"Department: {at[4]}<br>Supervisor: {at[5]}<br>"
            f"Period: {at[6]} → {at[7]}<br>Status: {at[8]}<br>Gender: {at[9]}")

    def _on_edit(self, row):
        if row >= len(self._attachees): return
        at = self._attachees[row]
        dlg = AddAttacheeDialog(self, data={
            "name":at[1],"reg_no":at[2],"institution":at[3],
            "department":at[4],"supervisor":at[5],
            "status":at[8],"gender":at[9]})
        dlg.attachee_saved.connect(lambda d,r=row: self._save_edit(r,d))
        dlg.exec()

    def _save_edit(self, row, data):
        old = self._attachees[row]
        self._attachees[row] = (
            old[0], data["name"], old[2], data["institution"],
            data["department"], data["supervisor"],
            data["start_date"], data["end_date"],
            data["status"], data["gender"])
        self._populate_table()

    def _on_delete(self, row):
        if row >= len(self._attachees): return
        name = self._attachees[row][1]
        reply = QtWidgets.QMessageBox.question(
            self,"Delete Attachee",
            f"Delete <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No)
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._attachees.pop(row)
            self._populate_table()

    def _on_quick(self, label):
        QtWidgets.QMessageBox.information(
            self, label, f"'{label}' will be available in the next sprint.")